// Create the accounts table with a JSONB doc column.
// Export an async function ensureSchema(client) that runs CREATE TABLE IF NOT EXISTS.
// Design: account_id TEXT PRIMARY KEY + doc JSONB NOT NULL + a GIN index on doc.
import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL
    )
  `);
  await client.query(`
    CREATE INDEX IF NOT EXISTS accounts_doc_gin ON accounts USING GIN (doc)
  `);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

export async function ensureSchema(db) {
  await db.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL
    )
  `);
}

export async function createAccounts(db, data) {
  const doc = {
    accountId: data.accountId,
    name: data.name,
    tier: data.tier,
    status: data.status,
    createdAt: data.createdAt || new Date().toISOString(),
  };
  await db.query(
    'INSERT INTO accounts (account_id, doc) VALUES ($1, $2)',
    [doc.accountId, JSON.stringify(doc)]
  );
  return doc;
}

export async function getAccounts(db, accountId) {
  const result = await db.query(
    'SELECT doc FROM accounts WHERE account_id = $1',
    [accountId]
  );
  return result.rows[0]?.doc ?? null;
}

export async function updateAccounts(db, accountId, updates) {
  const result = await db.query(
    'UPDATE accounts SET doc = doc || $2::jsonb WHERE account_id = $1 RETURNING doc',
    [accountId, JSON.stringify(updates)]
  );
  return result.rows[0]?.doc ?? null;
}

export async function deleteAccounts(db, accountId) {
  const result = await db.query(
    'DELETE FROM accounts WHERE account_id = $1',
    [accountId]
  );
  return result.rowCount > 0;
}

